INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Propolis Synergy Toner', 'COSRX', 'toner', 'pump', 'vedette offre des bienfaits anti-inflammatoires, antibactériens et réparateurs. Sa texture semblable à celle d''une essence est légère, non collante et pénètre rapidement. Recommandé pour : Peaux sèches, peaux déshydratées, peaux ternes. Peut être utilisé pour : Tous types de peaux. Conseils d''utilisation : Distribue une quantité de produit suffisante sur un coton. Passe-le sur l''ensemble de ton visage en suivant ton grain de peau. Retourne le coton et tapote doucement pour absorber l''excédent de produit." Ingrédients : Extrait de Propolis, Extrait de Miel, Butylène Glycol, 1,2-Hexanediol, Glycérine, Bétaïne, Extrait de Graines de Cassia Obtusifolia, Panthénol, Laurate de Polyglycéryl-10, Myristate de Polyglycéryl-10, Éthylhexylglycérine, Hyaluronate de Sodium, Copolymère d''Acrylate d''Hydroxyéthyle/Sodium Acryloyldiméthyl Taurate, Triglycéride Caprylique/Caprique.', 'Le Propolis Synergy Toner COSRX est un tonique quotidien formulé avec 72,6 % d''extrait de propolis d''abeille noire et 10 % d''extrait de miel pour une peau éclatante et lisse. Avec la teneur la plus élevée possible en extrait de propolis, cet ingrédient vedette offre des bienfaits anti-inflammatoires, antibactériens et réparateurs. Sa texture semblable à celle d''une essence est légère, non collante et pénètre rapidement. Recommandé pour : Peaux sèches, peaux déshydratées, peaux ternes. Peut être utilisé pour : Tous types de peaux.', 150, 'ml', 'cosrx-full-fit-propolis-synergy-toner', 'https://korean-skincare.fr/products/cosrx-full-fit-propolis-synergy-toner', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/019000000172_b4a9a18a-915c-42f0-8613-226a310be7ab.jpg?v=1751276155', 'Distribue une quantité de produit suffisante sur un coton. Passe-le sur l''ensemble de ton visage en suivant ton grain de peau. Retourne le coton et tapote doucement pour absorber l''excédent de produit."', 1439, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Centella Blemish Cream', 'COSRX', 'spot-treatment', 'tube', 'Eau de feuille de Centella Asiatica, Butylène Glycol, Glycérine, Huile de Graines d''Helianthus Annuus (Tournesol), Oxyde de Zinc, Diméthicone, Bétaïne, 1,2-Hexanediol, Extrait de Viola Tricolor, Huile de Palme Elaeis Guineensis, Huile de Noyau de Palme Elaeis Guineensis, Alcool Cétéarylique, Cetearyl Olivate, Sorbitan Olivate, Extrait de Centella Asiatica, PCA de Zinc, Copolymère Acrylate d''Hydroxyéthyl/Sodium Acryloyldiméthyl Taurate, Gomme Xanthane, Huile de Feuilles de Melaleuca Alternifolia (Arbre à Thé), Extrait de Racine de Scutellaria Baicalensis.', 'La Centella Blemish Cream COSRX est un traitement des boutons à action rapide composé d''oxyde de zinc et d''eau de feuille de Centella Asiatica qui aident à régulariser la production de sébum en calmant les zones à problèmes et en désincrustant les pores, tout en prévenant les boutons et la perte d''hydratation. Ce traitement améliore l''apparence de l''acné et des imperfections et soulage la peau stressée. Idéal pour les peaux sensibles et à tendance acnéique, il peut être utilisé à plusieurs fins - traitement des taches, élimination des cicatrices d''acné ou apaisement de la peau après l''extraction des comédons et des points noirs.', 30, 'ml', 'centella-blemish-cream', 'https://korean-skincare.fr/products/centella-blemish-cream', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/019000000028_b9d004cb-d531-4b2c-a21d-645bc65b814c.jpg?v=1751279780', 'Prélève une quantité adéquate de crème et applique une couche épaisse sur les zones à problèmes et à imperfections.', 1895, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Hyaluronic Acid Hydra Power Essence', 'COSRX', 'essence', 'dropper', 'Eau d''Hippophae Rhamnoides, Butylène Glycol, Glycérine, 1,2-Hexanediol, Hyaluronate de Sodium, Panthénol, Ethyl Hexanediol.', 'Hautement concentrée en acide hyaluronique, cette essence en gel sans huile offre une hydratation durable.', 100, 'ml', 'cosrx-hyaluronic-hydra-power-essence', 'https://korean-skincare.fr/products/cosrx-hyaluronic-hydra-power-essence', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_66f739e7-2da8-4892-aff4-c95917118b6c.jpg?v=1751277954', 'Après avoir nettoyé ton visage et utilisé un tonique, applique une petite quantité sur l''ensemble de ton visage. Tapote délicatement du bout des doigts pour faciliter l''absorption, puis applique ta crème hydratante.', 1345, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Centella Asiatica Calming Mask', 'Beauty of Joseon', 'mask', 'pack', 'Hanbang (médecine traditionnelle coréenne à base de plantes) tels que l''armoise, le ginseng et les baies de goji sont également présents pour apaiser et apporter des nutriments à la peau. Recommandé pour : Tous types de peaux. Conseils d''utilisation : Nettoie ton visage et utilise un tonique avant d''appliquer le masque. Déplie le masque tissu et place-le sur ton visage en faisant correspondre les découpes avec tes yeux, ton nez et ta bouche. Assieds-toi et détends-toi pendant 15 à 25 minutes. Laisse les ingrédients calmants et apaisants faire leur travail. Retire le masque et jette-le. Fais pénétrer délicatement l''excédent d''essence dans ton visage pour une absorption optimale. Ingrédients : Eau, Extrait de Centella Asiatica, Glycérine-26, Butylène Glycol, Niacinamide, 1,2-Hexanediol, HydroxyacétoPhenone, Arginine, Crosspolymère d''Acrylates/C10-30 Alkyl Acrylate, Hydroxyéthylcellulose, Carraghénane, Caprate de Polyglycéryl-4, Caprylate de Polyglycéryl-6, Adénosine, Éthylhexylglycérine, Disodium EDTA, Huile de Graine de Tournesol (Helianthus Annuus), Panthénol, Extrait de Feuille d''Artemisia Princeps, Extrait de Fruit de Lycium Chinense, Propanediol, Extrait de Portulaca Oleracea, Extrait de Racine de Ginseng (Panax Ginseng), Extrait de Feuille de Thé Vert (Camellia Sinensis), Huile de Fleur de Camomille Romaine (Anthemis Nobilis), Hyaluronate de Sodium, Acide Hyaluronique Hydrolysé, Acide Hyaluronique.', 'Le Centella Asiatica Calming Mask Beauty of Joseon est un masque tissu léger et rafraîchissant qui aide à hydrater et à apaiser la peau. Ce masque contient 15 % d''extrait de Centella Asiatica pour calmer les problèmes de peau, ainsi que 3 types d''acide hyaluronique pour une hydratation intense. Des ingrédients Hanbang (médecine traditionnelle coréenne à base de plantes) tels que l''armoise, le ginseng et les baies de goji sont également présents pour apaiser et apporter des nutriments à la peau. Recommandé pour : Tous types de peaux.', 1, 'pcs', 'beauty-of-joseon-centella-asiatica-calming-mask', 'https://korean-skincare.fr/products/beauty-of-joseon-centella-asiatica-calming-mask', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/CentellaMask800_8d967a55-a841-4185-b5aa-d50cbdc7db83.jpg?v=1751272552', 'Nettoie ton visage et utilise un tonique avant d''appliquer le masque. Déplie le masque tissu et place-le sur ton visage en faisant correspondre les découpes avec tes yeux, ton nez et ta bouche. Assieds-toi et détends-toi pendant 15 à 25 minutes. Laisse les ingrédients calmants et apaisants faire leur travail. Retire le masque et jette-le. Fais pénétrer délicatement l''excédent d''essence dans ton visage pour une absorption optimale.', 292, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Volcanic BHA Pore Cleansing Foam', 'INNISFREE', 'cleanser', 'tube', 'Water, Glycerin, Myristic Acid, Lauric Acid, Potassium Hydroxide, Kaolin, Stearic Acid, Glyceryl Stearate, Lauryl Hydroxysultaine, Glycol Distearate, Palmitic Acid, Lauryl Glucoside, Polyquaternium-22, Fragrance, Salicylic Acid, Silica, Onsen-sui, Zinc PCA, Volcanic Ash, Disodium EDTA, Propanediol, Lactic Acid/Glycolic Acid Copolymer, 1,2-Hexanediol, Madecassoside, Polyquaternium-10, Ethylhexylglycerin', 'La Volcanic Pore BHA Cleansing Foam Innisfree est une mousse nettoyante douce et profonde dont la formule contient de la cendre volcanique de Jeju et du BHA qui absorbe l''excès de sébum pour permettre l''élimination complète des impuretés qui obstruent les pores. Elle élimine efficacement les impuretés des pores tout en apaisant les problèmes de peau. Elle a été testée hypoallergénique et contre l''irritation de la peau pour garantir sa compatibilité avec les peaux sensibles.', 150, 'g', 'innisfree-volcanic-pore-bha-cleansing-foam', 'https://korean-skincare.fr/products/innisfree-volcanic-pore-bha-cleansing-foam', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes2_abd5667e-087d-4a6f-a3d2-4a07be39b896.jpg?v=1751281537', 'Applique une quantité appropriée sur tes mains mouillées et fais mousser abondamment. Après avoir massé ta peau, rince-la à l''eau tiède.', 1495, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'DIVE-IN Low Molecular Hyaluronic Acid Mask', 'Torriden', 'mask', 'pack', 'respectueux de la peau comme le panthénol, l''allantoïne et le tréhalose, qui non seulement maintiennent les niveaux d''hydratation de ta peau, mais apaisent également les irritations. Le masque en biocellulose adhère parfaitement à ton visage, garantissant l''absorption rapide de ces ingrédients actifs, ce qui en fait un complément essentiel à ta routine beauté. Ce masque à l''acide hyaluronique Torriden se distingue par son tissu en biocellulose souple et flexible. Cette composition unique retient et délivre efficacement l''essence hydratante d''acide hyaluronique à ta peau, garantissant ainsi une expérience de soin luxueuse et agréable. Après chaque utilisation, ta peau se sent rafraîchie et rajeunie, sans être grasse ou collante. De plus, ce masque est exempt de parfum artificiel, de colorants, de parabènes, d''huiles minérales et d''alcool isopropylique, ce qui fait qu''il convient même aux types de peau les plus sensibles. Incorpore ce masque à ta routine quotidienne pour apaiser, rafraîchir et hydrater ta peau en profondeur tout en réduisant la sensibilisation et les rougeurs pour un teint plus vibrant et plus jeune. Recommandé pour : Peaux sensibles, peaux sujettes à l''acné fungale, tous types de peaux. Conseils d''utilisation : Après avoir nettoyé ton visage et utilisé un tonique, applique le masque tissu, en l''ajustant à ton visage et en évitant le contour des yeux et des lèvres. Retire le masque au bout de 15 à 20 minutes. Tapote délicatement ta peau pour améliorer l''absorption. Ingrédients : Water, Butylene Glycol, Glycerin, Dipropylene Glycol, Sodium Hyaluronate Crosspolymer, Sodium Hyaluronate, Sodium Acetylated Hyaluronate, Hydrolyzed Sodium Hyaluronate, Hydrolyzed Hyaluronic Acid, Panthenol, Trehalose, Allantoin, Chamomilla Recutita (Matricaria) Flower Extract, Calendula Officinalis Flower Extract, Melia Azadirachta Leaf Extract, Melia Azadirachta Flower Extract, Coccinia Indica Fruit Extract, Solanum Melongena (Eggplant) Fruit Extract, Ocimum Sanctum Leaf Extract, Curcuma Longa (Turmeric) Root Extract, Corallina Officinalis Extract, Glyceryl Acrylate/Acrylic Acid Copolymer, PVM/MA Copolymer, Saccharide Isomerate, Carbomer, Xanthan Gum, Tromethamine, Pentylene Glycol, 1,2-Hexanediol, Hydroxyacetophenone, Portulaca Oleracea Extract, Malachite Extract, Ethylhexylglycerin', 'Le DIVE-IN Low Molecular Hyaluronic Acid Mask Torriden est un masque tissu rajeunissant et hydratant en profondeur. Ce masque tissu est une délicatesse de luxe pour ta peau, saturée d''un sérum enrichi de cinq types d''acides hyaluroniques. Ces puissants acides hyaluroniques agissent harmonieusement pour apporter à ta peau une hydratation profonde et un effet revitalisant, laissant ton teint rebondi et éclatant. De plus, ce masque est rempli d''ingrédients respectueux de la peau comme le panthénol, l''allantoïne et le tréhalose, qui non seulement maintiennent les niveaux d''hydratation de ta peau, mais apaisent également les irritations. Le masque en biocellulose adhère parfaitement à ton visage, garantissant l''absorption rapide de ces ingrédients actifs, ce qui en fait un complément essentiel à ta routine beauté. Ce masque à l''acide hyaluronique Torriden se distingue par son tissu en biocellulose souple et flexible. Cette composition unique retient et délivre efficacement l''essence hydratante d''acide hyaluronique à ta peau, garantissant ainsi une expérience de soin luxueuse et agréable. Après chaque utilisation, ta peau se sent rafraîchie et rajeunie, sans être grasse ou collante. De plus, ce masque est exempt de parfum artificiel, de colorants, de parabènes, d''huiles minérales et d''alcool isopropylique, ce qui fait qu''il convient même aux types de peau les plus sensibles. Incorpore ce masque à ta routine quotidienne pour apaiser, rafraîchir et hydrater ta peau en profondeur tout en réduisant la sensibilisation et les rougeurs pour un teint plus vibrant et plus jeune. Recommandé pour : Peaux sensibles, peaux sujettes à l''acné fungale, tous types de peaux.', 1, 'pcs', 'torriden-dive-in-low-molecular-hyaluronic-acid-mask', 'https://korean-skincare.fr/products/torriden-dive-in-low-molecular-hyaluronic-acid-mask', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_deda9a3d-21fa-4a95-982b-2ded395f669f.jpg?v=1751272556', 'Après avoir nettoyé ton visage et utilisé un tonique, applique le masque tissu, en l''ajustant à ton visage et en évitant le contour des yeux et des lèvres. Retire le masque au bout de 15 à 20 minutes. Tapote délicatement ta peau pour améliorer l''absorption.', 295, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'DIVE-IN Low Molecular Hyaluronic Acid Serum', 'Torriden', 'serum', 'dropper', 'Eau, Butylène Glycol, Glycérine, Dipropylène Glycol, 1,2-Hexanediol, Panthénol, Hyaluronate de Sodium, Acide Hyaluronique Hydrolysé, Hyaluronate de Sodium Acétylé, Hyaluronate de Sodium Réticulé, Hyaluronate de Sodium Hydrolysé, Allantoïne, Tréhalose, Bétaïne, Propanediol, Extrait de Portulaca Oleracea, Extrait de Hamamelis Virginiana, Madécassoside, Acide Madécassique, Céramide NP, Bêta-Glucane, Extrait de Malachite, Cholestérol, Pentylène Glycol, Copolymère Acrylate de Glycéryle/Acide Acrylique, Copolymère PVM/MA, Laurate de Polyglycéryl-10, Gomme Xanthane, Trométhamine, Carbomère, Ethylhexylglycérine, Extrait de Racine de Scutellaria Baicalensis, Extrait de Racine de Paeonia Suffruticosa.', 'Dévoile un univers d''hydratation et de revitalisation sans pareil pour ta peau avec le DIVE-IN Low Molecular Hyaluronic Acid Serum Torriden. Ce sérum est plus qu''un simple produit de soin pour la peau ; c''est un élixir transformateur conçu pour faire de ta routine beauté quotidienne un rituel de plaisir et de bien-être. Son arme secrète ? L''acide hyaluronique 5D-Complex révolutionnaire, qui désaltère rapidement ta peau et lui procure un regain d''hydratation instantané. Mais ce sérum est plus qu''une simple soin hydratant, c''est un également baume apaisant pour lutter contre tous tes problèmes de peau. Enrichi en D-panthénol, allantoïne et madécassoside, il va au-delà de l''hydratation, apaise les irritations et redonne vie à ton teint. Sa teinte bleu pastel unique, dérivée de l''extrait de malachite naturellement présente, ajoute une touche de mystique à ton rituel de soin tout en fournissant une protection supplémentaire à ta peau, renforçant ainsi sa vitalité et sa résistance. Ce qui distingue vraiment ce sérum, c''est son absorption impeccable, qui ne laisse aucune trace collante. Il révolutionne ta routine beauté en formant une barrière protectrice contre la perte d''hydratation grâce au céramide NP et au bêta-glucane. Incorpore ce sérum à ta routine quotidienne après avoir nettoyé ton visage et utilisé un tonique, et observe ta peau devenir lumineuse et éclatante. Le DIVE-IN Low Molecule Hyaluronic Acid Serum Torriden n''est pas seulement un soin pour la peau ; c''est une incitation à apprécier ta beauté unique et à débloquer tout le potentiel de ta peau pour lui donner éclat et sérénité. Recommandé pour : Tous types de peaux.', 50, 'ml', 'dive-in-low-molecular-hyaluronic-acid-serum', 'https://korean-skincare.fr/products/dive-in-low-molecular-hyaluronic-acid-serum', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_259b2acf-d634-465c-a6e2-c206615bd344.jpg?v=1751270792', 'Utilise le compte-gouttes pour prélever 3 à 5 gouttes de sérum et les répartir uniformément sur l''ensemble de ton visage. Applique plusieurs couches sur ton visage pour un meilleur effet hydratant.', 2295, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Madagascar Centella Hyalu-Cica Blue Serum', 'SKIN1004', 'serum', 'dropper', 'Eau purifiée, Eau de feuille de Centella Asiatica (38%), Butylène Glycol, 1,2-Hexanediol, Niacinamide, Glycérine, Pantolactone, Extrait de Fruit d''Hibiscus Esculentus, Hyaluronate de Sodium, Acide Hyaluronique Hydrolysé, Acide Hyaluronique, Méthylpropanediol, Panthénol, Cetearyl Olivate, Carbomer, Arginine, Sorbitan Olivate, Triglycéride Caprylique/Capric, Extrait de Fruit de Pyrus Communis (Poire), Glycol Pentylène, Adénosine, Acide Polyglutamique, Eau de Fleur de Rosa Damascena, Extrait de Feuille d''Artemisia Princeps, Extrait de Fruit de Cucumis Melo (Melon), Extrait de Racine d''Iris Florentina, Éthyl Hexyl Glycérine, Extrait de Feuille/Tige d''Hedera Helix (Lierre), Phytate de Sodium, Gomme Xanthane, Maltodextrine, Extrait Hydrolysé de Fruit de Gardenia Florida, Lécithine Hydrogénée, Céramide-NP, Hyaluronate de Sodium Crosspolymère, Hyaluronate de Sodium Hydrolysé.', 'Le Madagascar Centella Hyalu-Cica Blue Serum SKIN1004 est un sérum très hydratant qui apaise et éclaircit également la peau. Rempli de cinq types d''acide hyaluronique et de cica de Madagascar, ce sérum hydrate et calme la peau. Les céramides de taille nanométrique empêchent l''hydratation de s''évaporer, tandis que le niacinamide et l''adénosine procurent des effets éclaircissants et anti-âge.', 30, 'ml', 'skin1004-madagascar-centella-hyalu-cica-blue-serum', 'https://korean-skincare.fr/products/skin1004-madagascar-centella-hyalu-cica-blue-serum', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes-30ml_782e9452-b9d9-4c3a-a82c-ef075be613b5.jpg?v=1771500908', 'Prélève une quantité adéquate de produit à l''aide du compte-gouttes. Masse délicatement ta peau en suivant son grain. Renouvelle l''application sur le contour des yeux secs.', 1254, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Hyaluronic Acid Low-pH Cleansing Foam', 'ISNTREE', 'cleanser', 'tube', 'Eau, Sodium Cocoyl Isethionate, Glycérine, Sodium Methyl Cocoyl Taurate, Distéarate de Glycol, Cocoate de Potassium, Glycinate de Cocoyle de Potassium, Caprylyl/Capryl Glucoside, Hyaluronate de Sodium, Acide Hyaluronique Hydrolysé, Hyaluronate de Hydroxypropyltrimonium, Crosspolymère de Hyaluronate de Sodium, Acide Hyaluronique, Hyaluronate d''Acétylé Sodium, Hyaluronate de Sodium Hydrolysé, Hyaluronate de Potassium, Butylène Glycol, Extrait de Feuille d''Eclipta Prostrata, Extrait de Laminaria Japonica, Extrait de Graine d''Amaranthus Caudatus, Extrait de Centella Asiatica, Extrait de Fruit de Ficus Carica, Extrait de Racine d''Ulmus Davidiana, 1,2-Hexanediol, Glycine, Sérine, Acide Glutamique, Acide Aspartique, Leucine, Alanine, Arginine, Lysine, Isoleucine, Phénylalanine, Proline, Thréonine, Tyrosine, Valine, Histidine, Cystéine, Méthionine, Glycyrrhizate Dipotassique, Bêta-Glucane, Panthénol, Céramide NP, Lécithine Hydrogénée, Fructo-oligosaccharides, Allantoïne, Extrait de Son de Oryza Sativa, Pentylène Glycol, Chlorure de Sodium, Hydroxyacétophénone, Acide Citrique, Disodium EDTA, Polyquaternium-39, Decylene Glycol, Éthylhexylglycérine.', 'La Hyaluronic Acid Low-pH Cleansing Foam Isntree est un nettoyant doux qui laisse la peau hydratée. Fabriqué avec le plus grand soin, ce nettoyant bénéficie d''une formulation légèrement acide qui permet de préserver l''équilibre naturel de la peau tout en offrant un nettoyage rafraîchissant. Ce nettoyant utilise huit types d''acide hyaluronique qui agissent harmonieusement pour créer un bouclier d''hydratation, préservant ainsi l''hydratation après le nettoyage. Il est également enrichi en acides aminés, qui non seulement hydratent mais améliorent également la texture de la peau, laissant la peau veloutée et douce. Avec un pH faible qui ressemble à celui d''une peau saine, ce nettoyant purifie efficacement, rétablissant l''équilibre délicat du ratio huile/eau de la peau pour un teint revitalisé et éclatant. Dès maintenant, améliore ta routine beauté avec cette mousse nettoyante exceptionnelle. Recommandé pour : Tous types de peaux.', 150, 'ml', 'hyaluronic-acid-low-ph-cleansing-foam', 'https://korean-skincare.fr/products/hyaluronic-acid-low-ph-cleansing-foam', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_7139ca49-509e-4b83-8c24-fb87a0addd0b.jpg?v=1751299534', 'Applique une quantité adéquate de nettoyant sur ton visage et masse délicatement en effectuant de légers mouvements circulaires. Rince à l''eau tiède.', 1757, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Vitamin Fruit Serum', 'I''m From', 'serum', 'dropper', 'hypoallergéniques et naturels le rend adapté aux peaux sensibles et permet d''obtenir un teint équilibré et net. Pour un effet renforcé, il est recommandé d''associer ce sérum au Vitamin Tree Water Gel, particulièrement bénéfique pour les peaux grasses ou sensibles qui ont besoin à la fois d''hydratation et de purification. Recommandé pour : Peaux sensibles, tous types de peaux. Conseils d''utilisation : Applique une quantité appropriée de produit uniformément sur ta peau, en évitant le contour des yeux et de la bouche. Tapote légèrement ta peau pour faciliter l''absorption. Ingrédients : Extrait de fruit d''argousier (Hippophae Rhamnoides), Méthylpropanediol, 1,2-Hexanediol, Glycérine, Niacinamide, Cyclohexasiloxane, Extrait de Portulaca Oleracea, Extrait de fruit de Malpighia Glabra, Extrait de Laminaria Japonica, Extrait de feuille d''Eclipta Prostrata, Extrait d''Acmella Oleracea, Extrait de feuille de Melia Azadirachta, Extrait de racine de Curcuma Longa, Extrait de feuille d''Ocimum Sanctum, Extrait de Corallina Officinalis, Huile d''argousier (Hippophae Rhamnoides), Lécithine hydrogénée, Copolymère d''acryloyldiméthyltaurate d''ammonium/VP, Gomme xanthane, Acétate de tocophéryle, Adénosine, Carbomer, Fructooligosaccharides, Disodium EDTA, Bêta-glucane, Trométhamine, Acide hyaluronique hydrolysé, Eau, Acide ascorbique, Éthylhexylglycérine.', 'Le Vitamin Fruit Serum I''m From est un élixir revitalisant qui exploite les puissants bienfaits de 86,7 % d''extraits d''argousier pour rajeunir et illuminer ta peau. Composé d''un mélange harmonieux d''extraits riches en vitamines, ce sérum nourrit en profondeur les peaux fatiguées et ternes, leur redonnant l''éclat et la vitalité de la jeunesse. En mettant l''accent sur l''éclaircissement et l''uniformisation du teint, cette formule cible les taches brunes, l''hyperpigmentation et les zones irrégulières, dévoilant ainsi un teint plus uniforme et plus radieux. Chargée d''antioxydants, elle agit comme un bouclier protecteur, luttant contre les radicaux libres et le vieillissement prématuré, laissant à ta peau une apparence saine et lumineuse. Sa texture légère et non grasse pénètre sans effort dans la peau, offrant une hydratation durable, garantissant une sensation de douceur, de souplesse et de revitalisation. Avec une concentration impressionnante de 74 % d''extrait d''argousier, réputé pour sa composition riche en vitamines, ce sérum redonne vie aux peaux ternes, en les hydratant et en leur donnant un éclat naturel. Les acides de fruits contenus dans la formule renforcent l''hydratation de la peau, tandis que la texture légère du sérum pénètre rapidement sans résidu collant ni sensation de picotement. Infusé avec une concentration élevée de 1032 mg de vitamine C provenant de l''argousier, ce sérum ne se contente pas d''éclaircir la peau, il la lisse et l''adoucit également. Sa liste d''ingrédients hypoallergéniques et naturels le rend adapté aux peaux sensibles et permet d''obtenir un teint équilibré et net. Pour un effet renforcé, il est recommandé d''associer ce sérum au Vitamin Tree Water Gel, particulièrement bénéfique pour les peaux grasses ou sensibles qui ont besoin à la fois d''hydratation et de purification. Recommandé pour : Peaux sensibles, tous types de peaux.', 30, 'ml', 'im-from-vitamin-fruit-serum-1', 'https://korean-skincare.fr/products/im-from-vitamin-fruit-serum-1', NULL, 'Applique une quantité appropriée de produit uniformément sur ta peau, en évitant le contour des yeux et de la bouche. Tapote légèrement ta peau pour faciliter l''absorption.', 2248, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'AHA BHA PHA 30 Days Miracle Toner', 'SOME BY MI', 'toner', 'pump', ', le tonique est testé dermatologiquement pour les peaux sensibles et a un pH optimal de 5,5. Recommandé pour : Peaux à tendance grasse, mixte et acnéique. Peut être utilisé pour : Tous types de peaux. Conseils d''utilisation : Après avoir nettoyé ton visage, distribue une quantité suffisante du tonique AHA BHA PHA 30 Days Miracle sur un coton. Passe délicatement le coton imbibé de tonique sur ton visage, en évitant le contour des yeux. Insiste zones sujettes aux éruptions cutanées ou à l''excès de sébum. Laisse ta peau absorber le tonique et poursuis avec ta routine de soins habituelle. Utilise-le quotidiennement pour un teint purifié et plus lisse. Ingrédients : Eau, Butylène Glycol, Dipropylène Glycol, Glycérine, Niacinamide, Extrait de Feuille de Melaleuca Alternifolia (Arbre à Thé), Benzyl Glycol, Caprate de Polyglycéryl-4, Citrate de Sodium, Urée Hydroxyéthylée, Xylitol, Allantoïne, Ethylhexylglycérine, 1,2-Hexanediol, Acide Citrique, Fructane, Extrait de Fruit de Carica Papaya (Papaye), Adénosine, Huile de Mentha Piperita (Menthe Poivrée), Extrait de Graine de Lens Esculenta (Lentille), Cétone de Framboise, Hyaluronate de Sodium, Acide Salicylique, Acide Lactobionique, Pentylène Glycol, Extrait d''Hamamelis Virginiana (Hamamélis), Extrait de Fleur de Nelumbo Nucifera (Lotus Sacré), Extrait de Nid d''Hirondelle, Caprylyl Glycol, Phenoxyéthanol, Ethyl Hexanediol', 'Ce tonique polyvalent est un produit phare de la marque : une bouteille s''en vend toutes les trois secondes ! Comme son nom l''indique, la formule contient trois types d''exfoliants chimiques (AHA, BHA et PHA) ainsi que des extraits de papaye et d''hamamélis pour stimuler efficacement le renouvellement cellulaire et garder une peau lisse et rayonnante. La présence d''extrait d''eau d''arbre à thé en forte concentration favorise également une peau nette et apaise les inflammations, tandis que l''adénosine et la niacinamide ciblent les rides et le teint terne. Malgré ses puissants ingrédients, le tonique est testé dermatologiquement pour les peaux sensibles et a un pH optimal de 5,5. Recommandé pour : Peaux à tendance grasse, mixte et acnéique. Peut être utilisé pour : Tous types de peaux.', 150, 'ml', 'aha-bha-pha-30-days-miracle-toner', 'https://korean-skincare.fr/products/aha-bha-pha-30-days-miracle-toner', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_eb57b0a9-2fec-432b-a990-65bb5dfe372f.jpg?v=1751272551', 'Après avoir nettoyé ton visage, distribue une quantité suffisante du tonique AHA BHA PHA 30 Days Miracle sur un coton. Passe délicatement le coton imbibé de tonique sur ton visage, en évitant le contour des yeux. Insiste zones sujettes aux éruptions cutanées ou à l''excès de sébum. Laisse ta peau absorber le tonique et poursuis avec ta routine de soins habituelle. Utilise-le quotidiennement pour un teint purifié et plus lisse.', 1660, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'AHA BHA PHA 30 Days Miracle Serum', 'SOME BY MI', 'serum', 'dropper', 'tels que le niacinamide, l''eau de feuilles de théier et les huiles végétales assurent l''hydratation, équilibrent la production de sébum et rehaussent l''éclat naturel de la peau. Recommandé pour : Peau sujette à l''acné, tous les types de peau. Conseils d''utilisation : Bien secouer avant l''utilisation. Applique un tonique sur ta peau après le nettoyage. Prélève une quantité suffisante de produit avec le compte-goutte et applique sur tes joues et ton front. Tapote délicatement pour une meilleure absorption. Ingrédients : Eau, Extrait de Centella Asiatica, Cetyl Ethylhexanoate, Triglycéride Caprylique/Caprique, Glycérine, Huile de Fruit d’Olea Europaea, Propanediol, Alcool, Butylène Glycol, 1,2-Hexanediol, Niacinamide, Eau de Feuille de Melaleuca Alternifolia, Chlorure de Sodium, Huile d’Écorce de Citrus Paradisi, Huile d’Écorce de Citrus Aurantium Dulcis, Extrait de Racine de Curcuma Longa, Extrait de Feuille de Melia Azadirachta, Ethylhexylglycerin, Extrait de Fleur de Melia Azadirachta, Disodium EDTA, Gomme Xanthane, Acide Lactobionique, Extrait de Feuille de Gaultheria Procumbens, Huile de Fleur de Pelargonium Graveolens, Huile de Boswellia Carterii, Pentylène Glycol, Extrait de Corallina Officinalis, Extrait d’Écorce de Melia Azadirachta, Extrait de Feuille de Camellia Sinensis, Huile d’Écorce d’Amyris Balsamifera, Huile de Graine de Camellia Oleifera, Huile de Fruit de Rosa Canina, Extrait de Feuille d’Ocimum Sanctum, Huile de Graine de Limnanthes Alba, Huile de Son de Oryza Sativa, Huile de Graine de Moringa Oleifera, Huile de Graine de Camellia Sinensis, Huile d’Amande Douce (Prunus Amygdalus Dulcis), Caprylyl Glycol, Lactate de Sodium, Acide Citrique, Sodium PCA, Extrait de Fruit de Vaccinium Macrocarpon, Acide Lactique, Acide Glycolique, Acide Malique, Extrait de Feuille d’Ocimum Basilicum, Extrait de Lavandula Angustifolia, Extrait de Syringa Vulgaris, Extrait de Houttuynia Cordata, Acide Pyruvique, Extrait de Rosmarinus Officinalis, Extrait d’Angelica Keiskei, Extrait de Racine d’Althaea Officinalis, Madecassoside, Acide Tartrique, Extrait de Racine de Scutellaria Baicalensis, Extrait de Racine de Polygonum Cuspidatum, Extrait de Racine de Glycyrrhiza Glabra, Extrait de Feuille de Rosmarinus Officinalis, Extrait de Fleur de Chamomilla Recutita, Limonene, Citronellol, Citral', 'Le sérum miracle 30 jours Some By Mi AHA BHA PHA est une formule puissante mais douce conçue pour calmer, éclaircir et améliorer la santé générale de votre peau. Avec 14,5 % d''extrait de Centella Asiatica, il apaise la peau irritée tout en favorisant un teint radieux et rafraîchi. Infusé d''un mélange d''huiles naturelles, d''extraits de plantes et d''un trio d''acides exfoliants AHA, BHA et PHA, ce sérum élimine efficacement les cellules mortes, désobstrue les pores et affine le grain de la peau sans l''irriter. D''autres ingrédients tels que le niacinamide, l''eau de feuilles de théier et les huiles végétales assurent l''hydratation, équilibrent la production de sébum et rehaussent l''éclat naturel de la peau. Recommandé pour : Peau sujette à l''acné, tous les types de peau.', 50, 'ml', 'aha-bha-pha-30-days-miracle-serum', 'https://korean-skincare.fr/products/aha-bha-pha-30-days-miracle-serum', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes-50ml_6413eed7-3aa7-4ea3-a235-8f79236934de.jpg?v=1761746709', 'Bien secouer avant l''utilisation. Applique un tonique sur ta peau après le nettoyage. Prélève une quantité suffisante de produit avec le compte-goutte et applique sur tes joues et ton front. Tapote délicatement pour une meilleure absorption.', 1714, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'AHA BHA PHA 14 Days Super Miracle Spot All Kill Cream', 'SOME BY MI', 'moisturizer', 'jar', 'Melaleuca Alternifolia Leaf Water, Centella Asiatica Extract, Glycerin, Water, Butylene Glycol, Niacinamide, Panthenol, Artemisia Princeps Leaf Extract, Centella Asiatica Leaf Extract, Lavandula Angustifolia Extract, Rosmarinus Officinalis Extract, Origanum Vulgare Flower/ Leaf/ Stem Extract, Thymus Vulgaris Extract, Sodium Hyaluronate, Hyaluronic Acid, Saccharide Isomerate, Fructan, Salicylic Acid, Madecassoside, Madecassic Acid, Asiaticoside, Asiatic Acid, Allantoin, Protease, Lipase, Adenosine, Lactobionic Acid, Citric Acid, Sorbitan Oleate, Caprylyl/ Capryl Glucoside, Polyisobutene, Microcrystalline Cellulose, Cellulose Gum, Glyceryl Acrylate/ Acrylic Acid Copolymer, Magnesium Aluminum Silicate, Sodium Acrylate/ Sodium Acryloyldimethyl Taurate Copolymer, Ammonium Acryloyldimethyltaurate/ VP Copolymer, 1,2-Hexanediol, Benzyl Glycol, Ethylhexylglycerin, Raspberry Ketone, Disodium EDTA, Mentha Piperita Oil, Limonene', 'La AHA BHA PHA 14 Days Super Miracle Spot All Kill Cream Some By Mi est un traitement anti-taches qui aide à traiter l''acné en éliminant les cellules mortes et en renforçant la barrière cutanée. Cette crème est formulée avec du truecica pour apaiser la peau et du d-panthénol pour aider à l''hydrater et à maintenir l''équilibre optimal de son ratio huile/eau. Avec une texture légère et claire semblable à un gel, la Super Miracle Sport All Kill Cream permet une application en douceur et un fini frais non gras.', 30, 'ml', 'some-by-mi-super-miracle-spot-all-kill-cream', 'https://korean-skincare.fr/products/some-by-mi-super-miracle-spot-all-kill-cream', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_947adfb3-b5ff-4553-b1bf-adb41bbbb7f8.jpg?v=1751279777', 'Lors de la dernière étape de ta routine beauté. Applique l''AHA BHA PHA 14 Days Super Miracle Spot All Kill Cream Some By Mi sur les zones à problèmes. Tapote délicatement pour faciliter l''absorption.', 1995, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'No.3 Super Glowing Essence Toner', 'Numbuzin', 'toner', 'pump', 'fermentés, il agit pour éclaircir et raffermir la peau terne et fatiguée, en aidant à réduire l''apparence des rides et ridules. Sa formule revitalisante fournit également des soins ciblés pour certains problèmes de peau spécifiques tels que la texture irrégulière et la sécheresse, laissant ta peau lisse et rafraîchie. Que tu sois confrontée à la sécheresse, à un teint inégal ou aux signes de l''âge, la No.3 Super Glowing Essence Toner Numbuzin est conçue pour t''aider à obtenir une peau radieuse et éclatante de jeunesse. Conseils d''utilisation : Distribue une quantité appropriée de tonique sur un coton ou dans ta main et passe-la sur ta peau préalablement nettoyée. Tu peux aussi verser 2 ou 3 gouttes de tonique dans la paume de ta main et tapoter doucement pour faire pénétrer le produit dans ta peau. Ingrédients : Eau, Dipropylène Glycol, Glycérine, 1,2-Hexanediol, Niacinamide, Butylène Glycol, Glycereth-26, Methyl Gluceth-20, Extrait de Spirée Ulmaria, Filtrat de Ferment de Graines de Haricot Lactococcus, Ferment de Riz Lactobacillus, Ferment de Chlorelle, Extrait de Ferment d''Algue Lactobacillus, Extrait de Ferment de Raisin Saccharomyces, Extrait de Ferment de Citrouille Lactobacillus, Extrait de Ferment de Soja Lactobacillus, Filtrat de Ferment d''Extrait de Soja Lactobacillus, Filtrat de Ferment de Riz Saccharomyces, Filtrat de Ferment d''Orge Saccharomyces, Ferment de Calcium Saccharomyces, Ferment de Laminaria Saccharina Saccharomyces, Filtrat de Ferment de Pomme de Terre Saccharomyces, Extrait de Ferment d''Eriodictyon Californicum Lactobacillus, Ferment d''Hyacinthe d''Eau Lactobacillus, Ferment de Farine de Seigle Lactobacillus, Filtrat de Ferment de Fleur d''Hibiscus Sabdariffa Lactobacillus, Filtrat de Ferment de Lait Lactobacillus, Filtrat de Ferment de Racine de Ginseng Panax Lactobacillus, Extrait de Ferment de Cerise Acerola Lactobacillus, Ferment Lactobacillus, Filtrat de Lysat de Ferment Lactococcus, Ferment Lactococcus, Extrait de Ferment Lactococcus, Lysat de Ferment Lactococcus, Ferment de Streptocoque Thermophilus, Filtrat de Ferment de Aureobasidium Pullulans, Filtrat de Ferment de Bifida, Extrait de Ferment de Radis Leuconostoc, Extrait de Ferment de Racine de Wasabia Japonica Lactobacillus, Extrait de Ferment de Fruit de Grenade Punica Granatum Lactobacillus, Filtrat de Ferment de Glutamate de Bacillus, Filtrat de Ferment de Son de Riz/Extrait de Soja Bacillus, Ferment de Riz Monascus, Extrait de Ferment de Son de Riz Saccharomyces, Ferment de Riz Saccharomyces, Filtrat de Ferment de Jus de Poire Lactobacillus, Filtrat de Lysat de Ferment Pichia, Extrait de Ferment d''Alteromonas, Filtrat de Ferment de Graine de Ma-yuen Coix Lacryma-Jobi Saccharomyces, Ferment de Protéine de Soja Saccharomyces, Extrait de Ferment de Sphingomonas, Ferment de Malachite Saccharomyces, Ferment de Saccharomyces, Filtrat de Ferment de Saccharomyces, Filtrat de Ferment de Saccharomyces, Ferment de Aspergillus, Filtrat de Ferment de Aspergillus/Glucose/Soja/Amidon, Huile de Fleur de Pelargonium Graveolens, Hyaluronate de Sodium, Laurate de Polyglyceryl-10, Alcool Cétéarylique, Bétaïne, Acrylates/C10-30 Alkyl Acrylate Crosspolymer, Trométhamine, Polyquaternium-51, Hydroxyéthylcellulose, Adénosine, Géraniol, Citronellol.', 'Si tu cherches un tonique performant, le No.3 Super Glowing Essence Toner Numbuzin est le choix parfait. Ce tonique puissant ne se contente pas de préparer et d''hydrater ta peau, il offre également tous les bienfaits nourrissants d''une essence. Formulé avec 50 types d''ingrédients fermentés, il agit pour éclaircir et raffermir la peau terne et fatiguée, en aidant à réduire l''apparence des rides et ridules. Sa formule revitalisante fournit également des soins ciblés pour certains problèmes de peau spécifiques tels que la texture irrégulière et la sécheresse, laissant ta peau lisse et rafraîchie. Que tu sois confrontée à la sécheresse, à un teint inégal ou aux signes de l''âge, la No.3 Super Glowing Essence Toner Numbuzin est conçue pour t''aider à obtenir une peau radieuse et éclatante de jeunesse.', 200, 'ml', 'numbuzin-no-3-super-glowing-essence-toner', 'https://korean-skincare.fr/products/numbuzin-no-3-super-glowing-essence-toner', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_493a5376-f2bc-46f0-b562-1591b8d3186a.jpg?v=1751308534', 'Distribue une quantité appropriée de tonique sur un coton ou dans ta main et passe-la sur ta peau préalablement nettoyée. Tu peux aussi verser 2 ou 3 gouttes de tonique dans la paume de ta main et tapoter doucement pour faire pénétrer le produit dans ta peau.', 1954, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'No.5 Vitamin Spotlight Sheet Mask', 'Numbuzin', 'mask', 'pack', 'Eau, Méthylpropanediol, Niacinamide, PEG/PPG-17/6 Copolymère, Extrait de Racine de Coptis Japonica, 1,2-Hexanediol, Hydroxyacétohémone, Hydroxyéthylurée, Isopentyldiol, Méthyl Gluceth-20, Carbomère, Allantoïne, Phosphate d''Ascorbyl de Sodium, Glutathion, Lécithine Hydrogénée, PEG-60 Huile de Ricin Hydrogénée, Gomme de Xanthane, Adénosine, Éthylhexylglycérine, Polyacrylate de Sodium, Glycol Butylène, Extrait de Centella Asiatica, Disodium EDTA, Hydroxyéthylcellulose, Méthyl Diisopropyl Propionamide, Acide Polyglutamique, Protéase, Céramide, Acide Ascorbique, Arbutine, Alpha-Bisabolol, Acide Hyaluronique.', 'Revitalise ta peau avec le No.5 Vitamin Spotlight Sheet Mask Numbuzin, infusé d''un puissant mélange de glutathion liposomal, de niacinamide et de vitamine C pour illuminer la peau terne et réduire l''apparence des taches brunes et des rougeurs. Ce masque ampoule hautement concentré au glutathion C procure un éclat hydratant tout en améliorant les irrégularités du teint. Formulé avec de l''allantoïne, de l''acide hyaluronique et des céramides, il emprisonne l''hydratation et apaise les irritations, laissant ta peau rafraîchie et radieuse. Grâce à son essence légère, ce masque tissu offre une luminosité durable et un teint sain et éclatant. Parfait pour un usage quotidien, il révèle une peau radieuse et équilibrée. Recommandé pour : Hyperpigmentation, peaux sensibles, tous types de peaux.', 1, 'pcs', 'numbuzin-no-5-vitamin-spotlight-sheet-mask', 'https://korean-skincare.fr/products/numbuzin-no-5-vitamin-spotlight-sheet-mask', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_99fbf487-0dd3-4a66-a8cd-387409c8ba48.jpg?v=1751274401', 'Après avoir nettoyé ta peau, utilise un tonique pour lisser ton grain de peau. Retire le masque et applique-le sur ton visage, en évitant le contour des yeux. Laisse reposer pendant 10 à 20 minutes, puis retire le masque. Tapote l''essence restante sur ta peau pour la faire pénétrer.', 295, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'No.3 Tingle-Pore Softening Sheet Mask', 'Numbuzin', 'mask', 'pack', 'riches en antioxydants, et profite d''une peau rafraîchie et rajeunie, comme tu le mérites. Conseils d''utilisation : Après le nettoyage, utilise un tonique pour lisser ton grain de peau. Sors le masque, enlève le film et applique-le sur ton visage en évitant le contour des yeux. Laisse poser pendant environ 10 minutes puis retire le masque. Tapote l''excédent d''essence sur ta peau pour la faire pénétrer. Ingrédients : Eau, Bifida Ferment Lysate, Galactomyces Ferment Filtrate, Methyl Gluceth-20, Glycérine, Glycereth-26, Niacinamide, PEG-90, 1,2-Hexanediol, Extrait de Feuille de Menthe Poivrée, Extrait d''Hamamélis de Virginie, Extrait de Feuille de Camellia Sinensis, Extrait de Fleur de Camomille Noble, Huile de Feuille de Cymbopogon Citratus, Huile de Branche/Feuille de Cupressus Sempervirens, Huile de Zeste d''Orange Douce, Huile de Lavandula Angustifolia, Huile de Feuille de Rosmarinus Officinalis, Huile d''Écorce de Cedrus Atlantica, Extrait de Ferment d''Alteromonas, Extrait de Lait de Chèvre, Extrait de Soie, Squalane, Hyaluronate de Sodium, Panthénol, Butylene Glycol, Polyglyceryl-3 Methylglucose Distearate, Polyglyceryl-3 Distearate, Citrate de Stéarate de Glyceryl, SE de Stéarate de Glyceryl, Caprylyl Glycol, Octyldodeceth-16, Gomme Xanthane, Carbomer, Trométhamine, Alcool, Éthylhexylglycérine, Adénosine, Disodium EDTA, Limonène, Linalol, Citral.', 'Le No.3 Tingle-Pore Softening Sheet Mask Numbuzin est une solution de soin innovante conçue pour rajeunir et revitaliser ta peau. Infusé du Tingle-Pore Complex™, un mélange unique d''extrait de feuille de menthe poivrée, de thé vert et d''huile de romarin, ce masque tissu aide à réduire l''apparence des pores et à améliorer la santé et l''aspect général de ta peau. En plus du Tingle-Pore Complex™, le No.3 Sheet Mask de Numbuzin contient également du galactose et du bifida riches en antioxydants, qui agissent ensemble pour adoucir et hydrater ta peau, lui donnant ainsi un aspect plus éclatant et rajeuni. Son tissu doux et respirant épouse confortablement les contours de ton visage, ce qui permet à sa formule nourrissante de pénétrer profondément dans tes pores pour un maximum de bienfaits. Ce masque tissu est spécifiquement formulé pour être adapté aux peaux sèches et matures, en leur apportant l''hydratation et la nutrition supplémentaires dont elles ont besoin pour paraître au mieux de leur forme. En seulement 20 minutes, tu pourras découvrir une peau plus lisse, plus claire et plus lumineuse grâce au No.3 Tingle-Pore Softening Sheet Mask Numbuzin. Alors pourquoi attendre ? Fais-toi plaisir et offre à ta peau toute l''attention et les soins qu''elle mérite avec le No.3 Tingle-Pore Softening Sheet Mask Numbuzin. Constate par toi-même les puissants bienfaits du Tingle-Pore Complex™ et des ingrédients riches en antioxydants, et profite d''une peau rafraîchie et rajeunie, comme tu le mérites.', 1, 'pcs', 'numbuzin-no-2-water-collagen-65-voluming-sheet-mask', 'https://korean-skincare.fr/products/numbuzin-no-2-water-collagen-65-voluming-sheet-mask', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_89799d5f-f1ed-436b-9ab1-aab983f5e2ea.jpg?v=1751313940', 'Après le nettoyage, utilise un tonique pour lisser ton grain de peau. Sors le masque, enlève le film et applique-le sur ton visage en évitant le contour des yeux. Laisse poser pendant environ 10 minutes puis retire le masque. Tapote l''excédent d''essence sur ta peau pour la faire pénétrer.', 349, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'No.3 Skin Softening Serum', 'Numbuzin', 'serum', 'dropper', 'spécial qui s''est révélé capable d''hydrater efficacement la peau, de stimuler son élasticité et de réduire l''apparence des rides. Grâce à sa formule légère, ce sérum nourrit et hydrate la peau en profondeur, la laissant douce et souple. Il en résulte un teint uniforme et d''apparence saine qui resplendit de vitalité et de jeunesse. Que tu sois aux prises avec la sécheresse, un teint inégal ou les signes de l''âge, le No.3 Skin Softening Serum Numbuzin est conçu pour t''aider à obtenir la peau radieuse et pleine de jeunesse que tu mérites. Conseils d''utilisation : Après le nettoyage, prépare ta peau avec un tonique. Distribue une quantité appropriée de produit et applique-le sur ton visage de façon uniforme. Ingrédients : Lysat de Ferment Bifida, Filtrat de Ferment Galactomyces, Butylène Glycol, Methyl Gluceth-20, Eau, Niacinamide, PEG-90, 1,2-Hexanediol, Glycérine, Squalane, Extrait de Ferment d''Alteromonas, Extrait de Soie, Extrait de Lait de Chèvre, Hyaluronate de Sodium, Panthénol, Adénosine, Glycereth-26, Gomme Xanthane, Distéarate de Polyglycéryl-3, Glyceryl Stearate SE, Citrate de Stéarate de Glycéryle, Distéarate de Methylglucose de Polyglycéryl-3, Carbomer, Trométhamine, Éthylhexylglycérine, Caprylyl Glycol, Tropolone, Disodium EDTA.', 'Le No.3 Skin Softening Serum Numbuzin est un puissant sérum réparateur qui a été spécialement formulé pour t''aider à obtenir une peau radieuse et d''apparence plus jeune. Ce produit extraordinaire se targue d''inclure du Galactomyces Bifida, un ingrédient spécial qui s''est révélé capable d''hydrater efficacement la peau, de stimuler son élasticité et de réduire l''apparence des rides. Grâce à sa formule légère, ce sérum nourrit et hydrate la peau en profondeur, la laissant douce et souple. Il en résulte un teint uniforme et d''apparence saine qui resplendit de vitalité et de jeunesse. Que tu sois aux prises avec la sécheresse, un teint inégal ou les signes de l''âge, le No.3 Skin Softening Serum Numbuzin est conçu pour t''aider à obtenir la peau radieuse et pleine de jeunesse que tu mérites.', 50, 'ml', 'numbuzin-no-3-skin-softening-serum', 'https://korean-skincare.fr/products/numbuzin-no-3-skin-softening-serum', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_a524d064-a130-4130-afde-5eb041c79b9f.jpg?v=1751315741', 'Après le nettoyage, prépare ta peau avec un tonique. Distribue une quantité appropriée de produit et applique-le sur ton visage de façon uniforme.', 2248, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'No.1 Pantothenic B5 Active Soothing Cream', 'Numbuzin', 'moisturizer', 'jar', 'Eau, Glycol Butylène, Glycérine, Niacinamide, Ethylhexanoate de Cétéyle, Carbonate de Dicaprylyle, 1,2-Hexanediol, Glycol Pentylène, Vinyl Diméthicone, Extrait de Centella Asiatica, Extrait de Chlorella Vulgaris, Extrait de Racine de Sophora Angustifolia, Extrait de Feuille de Melia Azadirachta, Extrait de Fleur de Melia Azadirachta, Extrait de Fruit de Coccinia Indica, Extrait de Feuille d''Ocimum Sanctum, Extrait de Racine de Curcuma Longa, Extrait de Fleur d''Aloe Barbadensis, Extrait de Fruit de Solanum Melongena, Extrait de Corallina Officinalis, Extrait de Feuille de Camellia Sinensis, Extrait de Feuille de Centella Asiatica, Extrait de Cladosiphon Okamuranus, Extrait d''Écorce de Salix Alba, Extrait de Houttuynia Cordata, Extrait de Graines de Coffea Arabica, Extrait de Feuille de Citrus Aurantium Bergamia, Extrait de Feuille de Pinus Densiflora, Alpha-Arbutine, Huile de Noyau d''Argania Spinosa, Huile de Graines de Sesamum Indicum, Extrait de Fruit de Serenoa Serrulata, Extrait de Racine de Glycyrrhiza Glabra, Caprylyl Méthicone, Érythritol, Panthénol, Copolymère Hydroxyéthyl Acrylate/Sodium Acryloyldimethyl Taurate, Diméthiconol, Polyméthylsilsesquioxane, Acrylates/C10-30 Crosspolymère d''Alkyl Acrylate, Glucose, Trométhamine, Silice, Fructooligosaccharides, Fructose, Éthylhexylglycérine, Phytate de Sodium, Copolymère de Glycéryle Acrylate/Acide Acrylique, Triglycéride Caprylique/Caprique, Lécithine Hydrogénée, Tocophérol, Glucoside de Décyl, Acide Pantothénique, Polyglycéryle-4 Caprate, Polyglycéryle-6 Caprylate, Zinc PCA, Méthyl Diisopropyl Propionamide, Bêta-Sitostérol.', 'La No.1 Pantothenic B5 Active Soothing Cream Numbuzin est une crème gel hydratante légère qui hydrate jusqu''à 130 heures tout en contrôlant l''excès de sébum et apaisant les peaux sensibles. Formulée avec de l''acide pantothénique pour contrôler l''excès de sébum et l''acné, elle aide à désincruster les pores obstrués et à prévenir les éruptions cutanées. Enrichie en niacinamide, en silice et en extrait de racine de Sophora Angustifolia, elle cible les problèmes de peau, réduit l''inflammation et estompe les imperfections sans laisser de résidu gras. Testée cliniquement pour réduire les éruptions de plus de 60 % en seulement 4 semaines, cette crème non comédogène est parfaite pour les peaux à tendance acnéique, grasses ou sensibles, car elle offre une hydratation durable et un contrôle équilibré du sébum. Recommandé pour : Tous types de peaux.', 80, 'ml', 'numbuzin-no-1-pantothenic-b5-active-soothing-cream', 'https://korean-skincare.fr/products/numbuzin-no-1-pantothenic-b5-active-soothing-cream', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_f57ed6be-7884-4e5d-86fe-f6698ba664ed.jpg?v=1751270789', 'Lors de la dernière étape de ta routine beauté, applique délicatement le produit sur ta peau en évitant le contour des lèvres et des yeux. Tapote légèrement ta peau pour faire pénétrer complètement le produit.', 2444, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'No.1 Pure-Full Calming Herb Toner', 'Numbuzin', 'toner', 'pump', 'Extrait de Centella Asiatica, Extrait de Houttuynia Cordata, Extrait de Racine de Glycyrrhiza Uralensis, 1,2-Hexanediol, Dipropylène Glycol, Propanediol, Butylène Glycol, Glycérine, Extrait de Hyacinthus Orientalis, Extrait de Racine de Polygonum Multiflorum, Carbomère, Hydroxyéthylcellulose, Arginine, Allantoïne, Disodium EDTA, Extrait de Fleur de Nymphaea Alba, Bétaïne, Panthénol', 'Apaise et hydrate ta peau avec le No.1 Pure-Full Calming Herb Toner Numbuzin, une formule douce enrichie en extraits de Houttuynia Cordata, de Centella Asiatica et de racine de réglisse pour réduire les rougeurs et calmer les irritations. Idéal pour les peaux sensibles et sujettes à l’acné, ce tonique équilibre les niveaux d’eau et de sébum tout en purifiant et hydratant la peau grâce à des extraits botaniques tels que la jacinthe et le Polygonum Multiflorum. Sa formule légère à faible pH lisse et rafraîchit le teint sans obstruer les pores, pour une peau nette, apaisée et éclatante. Recommandé pour : Peaux sensibles, sans risque pour l''acné fongique, tous types de peaux.', 300, 'ml', 'numbuzin-no-1-pure-full-calming-herb-toner', 'https://korean-skincare.fr/products/numbuzin-no-1-pure-full-calming-herb-toner', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_ee50782b-d34b-4193-8be2-81c555c4c7fb.jpg?v=1751310345', 'Après le nettoyage, imbibe un coton d’une quantité généreuse de produit et passe-le délicatement du centre de ton visage vers l’extérieur, en évitant le contour des yeux et de la bouche. Tu peux aussi appliquer une quantité appropriée dans tes mains, puis tapoter légèrement sur ton visage jusqu’à absorption, en évitant le contour des yeux et de la bouche.', 2795, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'No.1 Easy Peasy Cleansing Oil', 'Numbuzin', 'cleanser', 'tube', 'Huile de Zea Mays, Myristate d''Isopropyle, Tétraoléate de Sorbeth-30, Palmitate d''Ethylhexyle, Triglycéride Caprylique/Caprique, Malate de Diisostéaryle, Sesquioleate de Sorbitane, Huile de graine de Macadamia Ternifolia, Huile de racine de Cyperus Esculentus, Huile de graine de Helianthus Annuus, Eau purifiée, Acétate de Tocophéryle, Parfum.', 'La No.1 Easy Peasy Cleansing Oil Numbuzin est la solution ultime pour éliminer facilement le maquillage et les impuretés de ta peau. Formulée avec un mélange d''huiles et d''extraits naturels, dont de l''huile de graines de Macadamia Ternifolia, cette huile nettoyante douce agit pour dissoudre même le maquillage le plus tenace, laissant à ta peau une sensation de propreté, de douceur et de fraîcheur. Sa formule légère glisse en douceur, éliminant sans effort la saleté, l''huile et le maquillage sans priver la peau de ses huiles naturelles. Elle est parfaite pour tous les types de peau et est particulièrement efficace pour éliminer le maquillage résistant à l''eau. De plus, elle possède un parfum agréable et subtil qui te laissera une sensation de bien-être et de ressourcement. Utilise la No.1 Easy Peasy Cleansing Oil Numbuzin comme première étape de ta routine beauté, en la massant sur peau sèche puis en la rinçant à l''eau tiède. Tu te retrouveras avec un teint propre et éclatant, prêt à accueillir le reste de tes produits de soin. Essaie-la dès aujourd''hui et découvre la facilité et l''efficacité de cette huile nettoyante extraordinaire !', 200, 'ml', 'numbuzin-no-1-easy-peasy-cleansing-oil', 'https://korean-skincare.fr/products/numbuzin-no-1-easy-peasy-cleansing-oil', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_4166364e-703c-4c9a-bc77-df8b82e08780.jpg?v=1751277975', 'Applique une quantité généreuse de produit sur ton visage sec et masse délicatement pour dissoudre ton maquillage de base. Ajoute un peu d''eau et masse encore pendant 10 secondes, jusqu''à ce que l''huile transparente devienne laiteuse. Rince à l''eau tiède.', 2346, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'No.1 Centella Re-Leaf Green Toner Pad', 'Numbuzin', 'toner', 'pack', 'clés comme l''extrait de Centella Asiatica, l''extrait de racine de réglisse et l''huile de feuille d''arbre à thé agissent en synergie pour atténuer les rougeurs et nourrir la peau en profondeur. Recommandé pour : Peaux à tendance acnéique, peaux sèches, tous types de peaux. Conseils d''utilisation : Après t''être lavé le visage, passe une compresse tonique en partant du milieu de ton visage vers l''extérieur, en évitant le contour des yeux et de la bouche. Tu peux aussi laisser poser la compresse sur ton visage pendant 3 à 5 minutes maximum, en évitant le contour des yeux et de la bouche. Ingrédients : Extrait de Centella Asiatica, Extrait de Racine de Glycyrrhiza Uralensis, Extrait de Houttuynia Cordata, Glycérine, Butylène Glycol, Dipropylène Glycol, Propanediol, 1,2-Hexanediol, Éthylhexylglycérine, Extrait de Hyacinthus Orientalis, Extrait de Racine de Polygonum Multiflorum, Carbomère, Hydroxyéthylcellulose, Polyglycéryl-10 Laurate, Polyglycéryl-10 Myristate, Arginine, Allantoïne, Disodium EDTA, Extrait de Fleur de Nymphaea Alba, Huile de Graines de Ricinus Communis, Bétaïne, Panthénol, Huile de Zeste de Citrus Paradisi, Huile de Fleur de Pelargonium Graveolens, Huile de Feuilles de Melaleuca Alternifolia, Huile de Feuilles de Rosmarinus Officinalis.', 'Profite du summum en matière de soin apaisant avec les No. 1 Centella Re-Leaf Green Toner Pads Numbuzin. Infusées de 89 % d''extraits de plantes, ces compresses vegan et biodégradables calment les irritations de la peau et réduisent les rougeurs, favorisant ainsi un teint sain et éclatant. Leur design à double face comporte des feuilles de cica d''un côté pour apaiser et un matériau à base de bambou de l''autre pour un regain d''hydratation instantané. Des ingrédients clés comme l''extrait de Centella Asiatica, l''extrait de racine de réglisse et l''huile de feuille d''arbre à thé agissent en synergie pour atténuer les rougeurs et nourrir la peau en profondeur. Recommandé pour : Peaux à tendance acnéique, peaux sèches, tous types de peaux.', 190, 'ml', 'numbuzin-no-1-centella-re-leaf-green-toner-pad', 'https://korean-skincare.fr/products/numbuzin-no-1-centella-re-leaf-green-toner-pad', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_0c70baf3-6b26-4b6f-b91d-ee976193b234.jpg?v=1751398533', 'Après t''être lavé le visage, passe une compresse tonique en partant du milieu de ton visage vers l''extérieur, en évitant le contour des yeux et de la bouche. Tu peux aussi laisser poser la compresse sur ton visage pendant 3 à 5 minutes maximum, en évitant le contour des yeux et de la bouche.', 2444, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Collagen Night Wrapping Mask', 'Medicube', 'mask', 'pack', 'Extrait de Collagène, Acide Hyaluronique, Niacinamide, Adénosine, Céramide NP, Eau/Aqua, Alcool Polyvinylique, Glycérine, Extrait de Tige d’Agave Americana, Hyaluronate de Sodium, 1,2-Hexanédiol, Caprylyl Glycol, Polyglycéryl-10 Laurate, Extrait de Chlorella Vulgaris, Glucose, Butylène Glycol, Ethylhexylglycérine, Fructooligosaccharides, Fructose, Gomme Xanthane, Extrait de Cynanchum Atratum, Triglycéride Caprylique/Caprique, Lécithine Hydrogénée, Extrait de Fleur d’Althaea Rosea, Céramide NP, Tocophérol, Extrait de Pancratium Maritimum, Extrait de Collagène, Glutamate de Sodium Stéaroyle.', 'Retrouve une peau plus ferme, hydratée et radieuse à ton réveil grâce au Collagen Night Wrapping Mask Medicube, un soin stimulant l''élasticité de la peau pendant la nuit, qui offre 8 heures de soins intensifs pendant ton sommeil. Formulé avec des extraits de collagène, du céramide NP et de l''adénosine, ce masque nourrit en profondeur, renforce la barrière cutanée et aide à réduire les ridules pour un teint jeune et rebondi. Grâce à son film de collagène unique qui retient l''hydratation et les nutriments, ta peau reste hydratée et résistante tout au long de la nuit. Sa formule facile à décoller s''enlève en un seul morceau, laissant ta peau rafraîchie et revitalisée au matin. Recommandé pour : Tous types de peaux.', 75, 'ml', 'medicube-collagen-night-wrapping-mask', 'https://korean-skincare.fr/products/medicube-collagen-night-wrapping-mask', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Product-page-sizes_1440119c-ddc2-48b5-b676-6f69a0c5111a.jpg?v=1768295115', 'Après avoir nettoyé ta peau le soir, applique le masque de nuit comme dernière étape avant de te coucher, en évitant le contour des yeux et de la bouche. Attends 15 minutes que le masque sèche avant de te coucher. Le lendemain matin, retire le masque en le décollant ou en nettoyant ton visage à l''eau tiède.', 1946, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'PDRN Pink Collagen Gel Mask', 'Medicube', 'mask', 'pack', 'antioxydants tels que l’acide ascorbique, le tocophérol et la carnosine. Il est formulé pour convenir aux peaux sensibles et aide à apaiser les irritations, réduire les rougeurs et laisser la peau lumineuse et repulpée après chaque utilisation. Recommandé pour : Peaux sensibles, tous types de peaux. Conseils d’utilisation : Nettoie ton visage et applique un tonique pour préparer ta peau. Retire le masque de son emballage et applique-le soigneusement sur ton visage, en alignant avec les yeux, le nez et la bouche. Laisse poser 10 à 20 minutes pour permettre à l’essence de pénétrer. Retire délicatement le masque et tapote légèrement le reste de l’essence sur ta peau jusqu’à absorption complète. Termine avec ta crème hydratante pour un confort optimal. Ingrédients : Eau, Glycérine, Méthylpropanediol, Copolymère d’Acrylates/Ethylhexyl Acrylate, Niacinamide, Poudre de Chondrus Crispus, 1,2-Hexanediol, Butylène Glycol, Bétaïne, Gomme de Caroube (Ceratonia Siliqua), Hydroxyacétophénone, Allantoïne, Glucomannane, Gomme Xanthane, Laureth-21, Panthénol, Polyglycéryl-10 Laurate, Propanediol, Gomme de Cellulose, Gomme de Guar (Cyamopsis Tetragonoloba), Parfum, Chlorure de Potassium, Dextrine, Adénosine, Ethylhexylglycérine, Collagène Hydrolysé, Cyanocobalamine, Acide Ascorbique, ADN de Sodium, Tocophérol, Acétyl Hexapeptide-8, Polypeptide d’Acide Ascorbique, Acétyl Octapeptide-3, Acétyl Tetrapeptide-2, Acétyl Tetrapeptide-3, Acétyl Tetrapeptide-5, Acétyl Tetrapeptide-9, Carnosine, Cuivre Tripeptide-1, Nonapeptide-1, Palmitoyl Pentapeptide-4, Palmitoyl Tripeptide-1, Palmitoyl Tripeptide-5', 'Le PDRN Pink Collagen Gel Mask Medicube est un masque tissu gélifié, conçu pour offrir une hydratation intense, de l’élasticité et un teint éclatant. Il contient du PDRN de saumon (polydeoxyribonucleotide) et du collagène hydrolysé à faible poids moléculaire pour aider à restaurer et raffermir la peau, tandis que le niacinamide et un mélange riche de peptides (Acetyl Hexapeptide-8, Acetyl Octapeptide-3, etc.) contribuent à illuminer, lisser les ridules et améliorer le teint. La texture gel du masque épouse parfaitement la peau et change de couleur du rose au transparent à mesure qu’il est absorbé, signalant une efficacité optimale. Ce masque soutient également la santé de la barrière cutanée grâce à des actifs apaisants comme l’allantoïne, le panthénol, la bétaïne, ainsi que des ingrédients antioxydants tels que l’acide ascorbique, le tocophérol et la carnosine. Il est formulé pour convenir aux peaux sensibles et aide à apaiser les irritations, réduire les rougeurs et laisser la peau lumineuse et repulpée après chaque utilisation. Recommandé pour : Peaux sensibles, tous types de peaux.', 1, 'pcs', 'medicube-pdrn-pink-collagen-gel-mask', 'https://korean-skincare.fr/products/medicube-pdrn-pink-collagen-gel-mask', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Medicube_PDRNPinkCollagenGelMask_Packshot.jpg?v=1759151112', 'Nettoie ton visage et applique un tonique pour préparer ta peau. Retire le masque de son emballage et applique-le soigneusement sur ton visage, en alignant avec les yeux, le nez et la bouche. Laisse poser 10 à 20 minutes pour permettre à l’essence de pénétrer. Retire délicatement le masque et tapote légèrement le reste de l’essence sur ta peau jusqu’à absorption complète. Termine avec ta crème hydratante pour un confort optimal.', 495, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Atobarrier 365 Cream', 'AESTURA', 'moisturizer', 'bar', 'Water, Butylene Glycol, Glycerine, Butylene Glycol Dicaprylate/Dicaprate, Cetyl Ethylhexanoate, Squalane, Pentaerythrityl Tetraisostearate, Dicaprylyl Carbonate, Behenyl Alcohol, Dimethicone, Hydroxypropyl Bispalmitamide MEA, Stearic Acid, Betaine, Mannitol, C14-22 Alcohols, Palmitic Acid, Hydroxypropyl Bislauramide Mea, Arachidyl Alcohol, Cholesterol, Polyacrylate-13, C12-20 Alkyl Glucoside, Allantoin, Arachidyl Glucoside, Niacinamide, Ceramide NP, Glyceryl Caprylate, Ethylhexylglycerin, Hydrogenated Polyisobutene, Carbomer, Tromethamine, Dimethiconol, Polyglyceryl-10 Laurate, Hydrogenated Lecithin, Ethylhexyl Palmitate, Acrylates/Ammonium Methacrylate Copolymer, Sorbitan Isostearate, Silica, Phytosphingosine, Sphingolipids, Arachidic Acid, Tocopherol, Oleic Acid', 'L''Atobarrier 365 Cream AESTURA est une crème hydratante réparatrice de barrière développée par des dermatologues, conçue pour fournir une hydratation intensive et longue durée aux peaux sèches et sensibles. Enrichie du complexe breveté Triple Lipid Complex, cette crème haute densité imite la structure lipidique naturelle de la peau avec des céramides, du cholestérol et des acides gras pour restaurer la fonction de barrière et prévenir la perte d’hydratation. Sa texture riche mais confortable fond sur la peau sans lourdeur, offrant jusqu’à 100 heures d’hydratation. Cliniquement testée pour les peaux sensibles, l''Atobarrier 365 Cream AESTURA aide à soulager la sensation de tiraillement, les desquamations et les irritations tout en renforçant la peau contre les agressions environnementales. Avec une utilisation régulière, elle favorise un teint plus lisse, plus sain et plus résistant, faisant de cette crème un incontournable des routines centrées sur la barrière cutanée. Recommandé pour : Peaux sèches ou très sèches, barrières cutanées compromises, et peaux sensibles.', 80, 'ml', 'aestura-atobarrier-365-cream', 'https://korean-skincare.fr/products/aestura-atobarrier-365-cream', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Aestura_Atobarrier365Cream_Packshot.jpg?v=1773819301', 'Applique une quantité appropriée comme dernière étape de ta routine beauté. Masse doucement sur ton visage et ton cou jusqu’à absorption complète. Utilise matin et soir.', 3095, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Atobarrier 365 Hydro Soothing Cream', 'AESTURA', 'moisturizer', 'bar', 'Water, Propanediol, Glycerin, Phenyl Trimethicone, Methyl Trimethicone, 1,2-Hexanediol, Trehalose, Dicaprylyl Carbonate, Ammonium Acryloyldimethyltaurate/VP Copolymer, Hydrogenated Lecithin, Hydrogenated Polyisobutene, Hydroxyethyl Acrylate/Sodium Acryloyldimethyl Taurate Copolymer, Cetearyl Alcohol, Acrylates/C10-30 Alkyl Acrylate Crosspolymer, Glyceryl Caprylate, Glyceryl Stearate, Tromethamine, Disodium EDTA, Ethylhexylglycerin, Stearic Acid, Palmitic Acid, Polyglyceryl-3 Methylglucose Distearate, Sorbitan Isostearate, Mannitol, Arginine, Serine, Sucrose, PCA, Citrulline, Glycogen, Histidine HCl, alanine, Tocopherol, Hydroxypropyl Bispalmitamide MEA, Threonine, Glutamic Acid, Myristic Acid, Arachidic Acid, Lysine HCl, Acrylates/Ammonium Methacrylate Copolymer, Cholesterol, Silica', 'L''Atobarrier 365 Hydro Soothing Cream AESTURA est une crème hydratante légère et rafraîchissante conçue pour apporter une hydratation profonde tout en renforçant la barrière cutanée. Grâce au Triple Lipid Complex breveté de la marque, cette formule gel-crème recharge les céramides essentiels, le cholestérol et les acides gras pour renforcer les défenses naturelles de la peau. Elle apporte un soulagement immédiat tout en maintenant une hydratation longue durée sans sensation de lourdeur. Avec sa texture rafraîchissante et rapidement absorbée, cette crème est parfaite pour une utilisation quotidienne, surtout dans les climats chauds ou pour ceux qui préfèrent une finition non grasse. L''Atobarrier 365 Hydro Soothing Cream AESTURA aide à calmer la sensibilité, réduire la sécheresse et laisse la peau équilibrée, lisse et confortablement hydratée tout au long de la journée. Recommandé pour : Peaux normales, mixtes, grasses, sensibles.', 60, 'ml', 'aestura-atobarrier-365-hydro-soothing-cream', 'https://korean-skincare.fr/products/aestura-atobarrier-365-hydro-soothing-cream', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Aestura_Atobarrier365HydroSoothingCream_Packshot.jpg?v=1773819301', 'Applique une quantité appropriée sur ton visage lors de la dernière étape de ta routine beauté. Tapote doucement jusqu’à absorption complète. Utilise matin et soir.', 3095, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Atobarrier 365 Bubble Cleanser', 'AESTURA', 'cleanser', 'bar', 'Water, Glycerin, Sorbitol, Propanediol, Coco-Glucoside, Caprylyl/Capryl Glucoside, Disodium Cocoamphodiacetate, Disodium Cocoyl Glutamate, Sodium Chloride, Citric Acid, Glyceryl Caprylate, Disodium EDTA, Ethylhexylglycerin, Butylene Glycol, Tocopherol, Camellia Sinensis Leaf Extract', 'L''Atobarrier 365 Bubble Cleanser AESTURA est un nettoyant moussant doux à faible irritation conçu pour éliminer efficacement les impuretés tout en protégeant la barrière d’hydratation naturelle de la peau. Formulé avec le Triple Lipid Complex breveté de la marque, ce nettoyant à bulles douces aide à maintenir un niveau d’hydratation optimal même après le nettoyage. Sa texture pré-moussée réduit les frottements sur la peau, le rendant particulièrement adapté aux peaux sensibles ou fragilisées. Cette formule douce mais efficace nettoie sans décaper, laissant la peau douce, équilibrée et confortablement hydratée. L''Atobarrier 365 Bubble Cleanser AESTURA soutient la santé de la barrière à chaque lavage, en faisant un nettoyant quotidien idéal pour maintenir une peau résistante et d’apparence saine. Recommandé pour : Peaux sensibles, barrière cutanée affaiblie, peaux sèches ou tiraillements.', 150, 'ml', 'aestura-atobarrier-365-bubble-cleanser', 'https://korean-skincare.fr/products/aestura-atobarrier-365-bubble-cleanser', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Aestura_Atobarrier365BubbleCleanser_Packshot.jpg?v=1773819302', 'Distribue une quantité appropriée de mousse dans tes mains et masse doucement sur la peau humide. Rince abondamment à l’eau tiède. Utilise matin et soir.', 2095, 'skincare') ON CONFLICT DO NOTHING;
INSERT INTO products (created_by, name, brand, kind, unit, inci, description, total_amount, amount_unit, slug, url, image_url, notes, price_cents, category) VALUES ('019de09c-3403-7f67-8b49-560aecb2d9c9', 'Atobarrier 365 Lotion', 'AESTURA', 'moisturizer', 'bar', 'Water, Butylene Glycol, Glycerin, Squalene, Pentaerythrityl Tetraisostearate, Cyclopentasiloxane, Polyglyceryl-3 Methylglucose Distearate, Butylene Glycol Dicaprylate/dicaprate, Caprylic/capric/stearic Triglyceride, Cyclohexasiloxane, Stearic Acid, Palmitic Acid, Glyceryl Stearate, Hydroxyethyl Acrylate/sodium Acryloyldimethyl Taurate Copolymer, Hydroxypropyl Bispalmitamide Mea, Polyglyceryl-10 Stearate, Dimethiconol, Cholesterol, Hydroxypropyl Bislauramide Mea, Behenyl Alcohol, Phytosphingosine, Glyceryl Caprylate, Carbomer, Disodium Edta, Ethylhexylglycerin, Tromethamine, Sorbitan Isostearate, Arachidic Acid, Myristic Acid, Mannitol, Copernicia Cerifera (Carnauba) Wax Extract., Tocopherol, Acrylates/ammonium Methacrylate Copolymer, Silica, Caesalpinia Sappan Stem Powder, Oleic Acid', 'L''Atobarrier 365 Lotion AESTURA est une formule légère mais profondément hydratante conçue pour renforcer et protéger la barrière cutanée tout en offrant une hydratation longue durée. Alimentée par le Triple Lipid Complex breveté, cette lotion réapprovisionne les céramides essentiels, le cholestérol et les acides gras pour aider à rétablir l’équilibre et prévenir la perte d’hydratation. Sa texture lisse et rapidement absorbée s’étale facilement et laisse la peau douce sans effet collant. Idéale pour le soin quotidien du visage et du corps, cette lotion polyvalente aide à soulager la sécheresse, les tiraillements et la sensibilité causés par les agressions environnementales. L''Atobarrier 365 Lotion AESTURA favorise une peau plus saine et résiliente avec une utilisation régulière, en faisant un essentiel quotidien fiable pour maintenir la force de la barrière et l’hydratation. Recommandé pour : Tous types de peaux.', 150, 'ml', 'aestura-atobarrier-365-lotion', 'https://korean-skincare.fr/products/aestura-atobarrier-365-lotion', 'https://cdn.shopify.com/s/files/1/0568/9802/7638/files/Aestura_Atobarrier365Lotion_Packshot.jpg?v=1773819302', 'Applique une quantité appropriée sur peau propre et masse doucement jusqu’à absorption complète. Utilise matin et soir, ou selon les besoins.', 3095, 'skincare') ON CONFLICT DO NOTHING;